FUNCTION_BLOCK AutomaticColorDetection_nichtfertig
VAR_INPUT
	MethodCall : BOOL;
	EmergencyStopSignal : BOOL;
	ColorSensor: INT;
	ColorCode_1: INT;
	ColorCode_2: INT;
	ColorCode_3: INT;
	OperatingMode : BOOL;
END_VAR

VAR_OUTPUT
	Color_1: BOOL;
	Color_2: BOOL;
	Color_3: BOOL;
END_VAR

VAR
END_VAR

implementation:
Color_1 := ((ColorSensor) = (ColorCode_1));
Color_2 := ((ColorSensor) = (ColorCode_2));
Color_3 := ((ColorSensor) = (Color_3));

R_TRIG_MethodCall(CLK := MethodCall);

ResetMethodCall := (
    (Direction AND (DI02_EncoderStart01 >= DI03_EncoderTarget01) AND (DI04_EncoderStart02 >= DI05_EncoderTarget02))
    OR ((NOT Direction) AND (DI02_EncoderStart01 <= DI03_EncoderTarget01) AND (DI04_EncoderStart02 <= DI05_EncoderTarget02))
    OR EmergencyStopSignal
    OR DI01
    OR InitStateDrive_Input
);

RS_AxisControl(
    SET := (
        R_TRIG_MethodCall.Q
        AND (
            (Direction AND (DI02_EncoderStart01 < DI03_EncoderTarget01) AND (DI04_EncoderStart02 < DI05_EncoderTarget02))
            OR ((NOT Direction) AND (DI02_EncoderStart01 > DI03_EncoderTarget01) AND (DI04_EncoderStart02 > DI05_EncoderTarget02))
            OR InitStateDrive_Input
        )
        AND OperatingMode
    ),
    RESET1 := ResetMethodCall
);

TOF_DigitalOutputControl(IN := RS_AxisControl.Q1, PT := TOF_Time_MotorControl);
DigitalOutputControl_01 := TOF_DigitalOutputControl.Q;

RS_TouchSensorRelief(
    SET := ((ResetMethodCall) AND (MethodCall) AND (TouchSensorRelief)),
    RESET1 := ((NOT DI01) OR EmergencyStopSignal OR InitStateDrive_Input)
);
TOF_TouchSensorRelief(IN := RS_TouchSensorRelief.Q1, PT := TOF_Time_TouchSensorRelief);
DigitalOutputControl_02 := TOF_TouchSensorRelief.Q;

R_TRIG_MethodCall(CLK := MethodCall);
ResetMethodCall := ((((Direction) AND (DI02))) OR (EmergencyStopSignal));
RS_AxisControl(
    SET := ((R_TRIG_MethodCall.Q) AND (((((Direction) AND (((DI01) OR (TouchSensorRelief))))) OR (((Direction) AND (InitStateDrive_Input))))) AND (OperatingMode)),
    RESET1 := ((((Direction) AND (DI02))) OR (EmergencyStopSignal))
);
TOF_DigitalOutputControl(IN := RS_AxisControl.Q1, PT := TOF_Time_MotorControl);
DigitalOutputControl_01 := TOF_DigitalOutputControl.Q;
R_TRIG_TSR(CLK := ((ResetMethodCall) AND (DI02) AND (MethodCall) AND (TouchSensorRelief)));
InitStateDriveFinished := ((NOT (DI02)) OR (EmergencyStopSignal));
RS_TouchSensorRelief(SET := R_TRIG_TSR.Q, RESET1 := ((NOT (DI02)) OR (EmergencyStopSignal)));
TOF_TouchSensorRelief(IN := RS_TouchSensorRelief.Q1, PT := TOF_Time_TouchSensorRelief);
DigitalOutputControl_02 := TOF_TouchSensorRelief.Q;
F_TRIG_0(CLK := DigitalOutputControl_01);
F_TRIG_1(CLK := DigitalOutputControl_02);

