R_TRIG_EncoderPos05_ValveOutput(CLK := DI07_EncoderStart05 = DI13_EncoderTarget05);
R_TRIG_EncoderPos06_ValveOutput(CLK := DI08_EncoderStart06 = DI14_EncoderTarget06);

bEncoderInputCondition :=
    R_TRIG_EncoderPos01_CompressorInput.Q
    AND R_TRIG_EncoderPos02_CompressorInput.Q
    AND R_TRIG_EncoderPos03_CompressorInput.Q
    AND R_TRIG_EncoderPos04_CompressorInput.Q
    AND R_TRIG_EncoderPos05_CompressorInput.Q
    AND R_TRIG_EncoderPos06_CompressorInput.Q;

bEncoderOutputCondition :=
    R_TRIG_EncoderPos01_CompressorOutput.Q
    AND R_TRIG_EncoderPos02_CompressorOutput.Q
    AND R_TRIG_EncoderPos03_CompressorOutput.Q
    AND R_TRIG_EncoderPos04_CompressorOutput.Q
    AND R_TRIG_EncoderPos05_CompressorOutput.Q
    AND R_TRIG_EncoderPos06_CompressorOutput.Q;

bStartCondition :=
    (DI01 OR bEncoderInputCondition OR InitStateDrive_Input)
    AND OperatingMode;

bResetCondition :=
    (Destination AND (DI02 OR bEncoderOutputCondition))
    OR EmergencyStopSignal;

ResetMethodCall := bResetCondition;

RS_Compressor(
    SET := R_TRIG_MethodCall.Q AND bStartCondition,
    RESET1 := bResetCondition
);

TON_Compressor_Control(
    IN := RS_Compressor.Q1,
    PT := TON_Time_Compressor
);

DigitalOutputControl_01 := TON_Compressor_Control.Q;

TON_SelfSet(
    IN := R_TRIG_MethodCall.Q AND PowerOFF_SelfSet,
    PT := TON_Time_PowerOFFSelfSet
);

RS_Valve(
    SET := R_TRIG_MethodCall.Q AND (DI01 OR bEncoderInputCondition OR InitStateDrive_Input),
    RESET1 := (Destination AND (DI02 OR bEncoderOutputCondition OR TON_SelfSet.Q)) OR EmergencyStopSignal
);

TON_Valve_Control(
    IN := RS_Valve.Q1,
    PT := TON_Time_Valve
);

DigitalOutputControl_02 := TON_Valve_Control.Q;

R_TRIG_MethodCall(CLK := MethodCall);
R_TRIG_MethodCall(CLK := MethodCall);
TOF_CuttingTime(IN := R_TRIG_MethodCall.Q, PT := TOF_Time_CuttingTime);
ResetMethodCall := ((TOF_CuttingTime.Q) OR (EmergencyStopSignal));
RS_CuttingProcess(SET := ((R_TRIG_MethodCall.Q) AND (((DI01) OR (InitStateDrive_Input))) AND (OperatingMode)), RESET1 := ((TOF_CuttingTime.Q) OR (EmergencyStopSignal)));
DigitalOutputControl_01 := RS_CuttingProcess.Q1;

R_TRIG_MethodCall(CLK := MethodCall);
R_TRIG_MethodCall(CLK := MethodCall);
TOF_HardeningTime(IN := R_TRIG_MethodCall.Q, PT := TOF_Time_HardeningTime);
ResetMethodCall := ((TOF_HardeningTime.Q) AND (EmergencyStopSignal));
RS_HardeningProcess(SET := ((R_TRIG_MethodCall.Q) AND (((DI01) OR (InitStateDrive_Input))) AND (OperatingMode)), RESET1 := ((TOF_HardeningTime.Q) AND (EmergencyStopSignal)));
DigitalOutputControl_01 := RS_HardeningProcess.Q1;

R_TRIG_MethodCall(CLK := MethodCall);
R_TRIG_MethodCall(CLK := MethodCall);
TON_SecuringProcessingTime(IN := R_TRIG_MethodCall.Q, PT := TON_Time_SecuringProcess);
RS_SecuringProcessCompressorON(SET := ((R_TRIG_MethodCall.Q) AND (((DI01) OR (InitStateDrive_Input))) AND (OperatingMode)), RESET1 := ((TON_SecuringProcessingTime.Q) OR (EmergencyStopSignal)));
TON_SecuringTime_Compressor(IN := RS_SecuringProcessCompressorON.Q1, PT := TON_Time_Securing);
DigitalOutputControl_01 := TON_SecuringTime_Compressor.Q;
R_TRIG_MethodCall(CLK := MethodCall);
R_TRIG_MethodCall(CLK := MethodCall);
TON_SecuringProcessingTime(IN := R_TRIG_MethodCall.Q, PT := TON_Time_SecuringProcess);
