TON_SecuringTime_Valve(IN := RS_SecuringProcessCompressorOFF.Q1, PT := TON_Time_Securing + T#0.5s);
DigitalOutputControl_02 := TON_SecuringTime_Valve.Q;

R_TRIG_MethodCall(CLK := MethodCall);
R_TRIG_MethodCall(CLK := MethodCall);
TOF_StampingTime(IN := R_TRIG_MethodCall.Q, PT := TOF_Time_StampingTime);
