FUNCTION_BLOCK VSG_DiagnosisHandler
VAR_INPUT
    Diagnose_gefordert : BOOL;
    ErrorDetectedRaw   : BOOL;
    Reset              : BOOL;
    PulseTime          : TIME := T#100MS;
END_VAR
VAR_OUTPUT
    Err_detected  : BOOL := FALSE;
    Diag_finished : BOOL := FALSE;
    Alt_found     : BOOL := FALSE;
    Busy          : BOOL := FALSE;
END_VAR
VAR
    rtReq      : R_TRIG;
    rtError    : R_TRIG;
    rtDiagAck  : R_TRIG;
    rtAltFound : R_TRIG;
    tpPulse    : TP;
