implementation:
rtReq(CLK := Diagnose_gefordert);
rtError(CLK := ErrorDetectedRaw);
rtDiagAck(CLK := OPCUA.Diag_finished);
rtAltFound(CLK := OPCUA.Alt_found);

IF Reset THEN
    Err_detected := FALSE;
    Diag_finished := FALSE;
    Alt_found := FALSE;
    Busy := FALSE;
    OPCUA.TriggerD2 := FALSE;
END_IF

IF rtError.Q THEN
    Err_detected := TRUE;
    Diag_finished := FALSE;
    Alt_found := FALSE;
	OPCUA.TriggerD2 := TRUE;
END_IF

IF rtReq.Q AND Err_detected AND NOT Busy THEN
    Busy := TRUE;
END_IF

IF OPCUA.TriggerD2 AND Diag_finished THEN
    OPCUA.TriggerD2 := FALSE;
END_IF

IF Busy AND rtDiagAck.Q THEN
    Diag_finished := TRUE;
    Alt_found := FALSE;
    Busy := FALSE;
    OPCUA.Diag_finished := FALSE;
    OPCUA.TriggerD2 := FALSE;
END_IF

IF Busy AND rtAltFound.Q THEN
    Alt_found := TRUE;
    Diag_finished := TRUE;
    Busy := FALSE;
    OPCUA.Alt_found := FALSE;
    OPCUA.TriggerD2 := FALSE;
END_IF

IF NOT Diagnose_gefordert AND (Diag_finished OR Alt_found) THEN
    Err_detected := FALSE;
    Diag_finished := FALSE;
    Alt_found := FALSE;
END_IF

