implementation:
VSG_InitDrive_Rotate_CW(
    MethodCall := MethodCall_InitDrive,
    EmergencyStopSignal := NOT ESS,
    Direction := DirectionRotation,
    InitStateDrive_Input := InputInitDriveMode,
    DI01 := FALSE,
    DI02 := TouchSensor01_Rotation,
    TouchSensorRelief := TSR,
    TOF_Time_MotorControl := T#0MS,
    TOF_Time_TouchSensorRelief := TOF_Time_TSR,
    OperatingMode := InitDriveMode
);

VSG_Init_RotateCW := VSG_InitDrive_Rotate_CW.DigitalOutputControl_01;
