	MethodCall_HardeningProcess : BOOL := FALSE; // used to store InputArg "MethodCall" from Start() method
	ResetMethodCall	: BOOL := FALSE;
	ProcessingTime_HardeningProcess : TIME;
	callCounterStart : ULINT; // counts how many times the Start() method has been called
