FUNCTION_BLOCK VSG_AS_CompressorControl
VAR
    MethodCall_CompressorControl : BOOL := FALSE;
    ResetMethodCall : BOOL := FALSE;

    Destination : BOOL := TRUE;

    EncoderTargetPosition01 : UDINT;
    EncoderTargetPosition02 : UDINT;
    EncoderTargetPosition03 : UDINT;
    EncoderTargetPosition04 : UDINT;
    EncoderTargetPosition05 : UDINT;
    EncoderTargetPosition06 : UDINT;

    callCounterStart : ULINT;
    callCounterCheckState : ULINT;
    callCounterAbort : ULINT;

    jobRunning : BOOL := FALSE;
    jobFinished : BOOL := FALSE;
    state : UDINT := 0;

    MBS_VSG_VerticalMove : CompressorControl;

    TON_TimeCompressor : TIME := T#0MS;
    TON_TimeValve : TIME := T#0MS;
    TON_TimePowerOffSelfSet : TIME := T#100MS;

    PowerOffSelfSet : BOOL := TRUE;
END_VAR

VAR_INPUT
    ESS : BOOL;

    EncoderStartPosition01 : UDINT;
    EncoderStartPosition02 : UDINT;
    EncoderStartPosition03 : UDINT;
    EncoderStartPosition04 : UDINT;
    EncoderStartPosition05 : UDINT;
    EncoderStartPosition06 : UDINT;

    WorkpieceAtPickupPosition : BOOL;
    AutomaticMode : BOOL;
END_VAR

VAR_OUTPUT
    DO_CompressorVSG : BOOL;
    DO_ValveVSG : BOOL;

    VSG_ErrorDetected : BOOL;
    VSG_ErrorCode : UDINT;
END_VAR

implementation:
//VSG_ErrorDetected := FALSE;
//VSG_ErrorCode := 0;

IF MethodCall_CompressorControl AND NOT WorkpieceAtPickupPosition THEN

    VSG_ErrorDetected := TRUE;
    VSG_ErrorCode := 1001;

    DO_CompressorVSG := FALSE;
    DO_ValveVSG := FALSE;

    MethodCall_CompressorControl := FALSE;
    ResetMethodCall := TRUE;

    jobRunning := FALSE;
    jobFinished := TRUE;
    state := 900;

ELSE

    MBS_VSG_VerticalMove(
        MethodCall := MethodCall_CompressorControl,
        EmergencyStopSignal := NOT ESS,
        Destination := Destination,
        InitStateDrive_Input := FALSE,

        DI01 := WorkpieceAtPickupPosition,
        DI02 := FALSE,

        DI03_EncoderStart01 := EncoderStartPosition01,
        DI04_EncoderStart02 := EncoderStartPosition02,
        DI05_EncoderStart03 := EncoderStartPosition03,
        DI06_EncoderStart04 := EncoderStartPosition04,
        DI07_EncoderStart05 := EncoderStartPosition05,
        DI08_EncoderStart06 := EncoderStartPosition06,

        DI09_EncoderTarget01 := EncoderTargetPosition01,
        DI10_EncoderTarget02 := EncoderTargetPosition02,
        DI11_EncoderTarget03 := EncoderTargetPosition03,
        DI12_EncoderTarget04 := EncoderTargetPosition04,
        DI13_EncoderTarget05 := EncoderTargetPosition05,
        DI14_EncoderTarget06 := EncoderTargetPosition06,

        PowerOFF_SelfSet := PowerOffSelfSet,
        TON_Time_PowerOFFSelfSet := TON_TimePowerOffSelfSet,
        TON_Time_Compressor := TON_TimeCompressor,
        TON_Time_Valve := TON_TimeValve,
        OperatingMode := AutomaticMode
    );

    DO_CompressorVSG := MBS_VSG_VerticalMove.DigitalOutputControl_01;
    DO_ValveVSG := MBS_VSG_VerticalMove.DigitalOutputControl_02;
    ResetMethodCall := MBS_VSG_VerticalMove.ResetMethodCall;

    IF ResetMethodCall THEN
        MethodCall_CompressorControl := FALSE;
        jobRunning := FALSE;
        jobFinished := TRUE;
        state := 100;
    END_IF;

END_IF;

