VSG_Skill_RotationMoveCCW(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_VSG.VSG_Ref_Schalter_drehen,
    EncoderStartPosition01 := GVL_VSG.VSG_Enc_drehen_I1,
    EncoderStartPosition02 := GVL_VSG.VSG_Enc_drehen_I2,
