    EncoderStartPosition01 := GVL_VSG.VSG_Enc_drehen_I1,
    EncoderStartPosition02 := GVL_VSG.VSG_Enc_drehen_I2,
    EncoderStartPosition03 := GVL_VSG.VSG_Enc_horizontal_I1,
    EncoderStartPosition04 := GVL_VSG.VSG_Enc_horizontal_I2,
    EncoderStartPosition05 := GVL_VSG.VSG_Enc_vertikal_I1,
    EncoderStartPosition06 := GVL_VSG.VSG_Enc_vertikal_I2,

    WorkpieceAtPickupPosition := GVL_HRL.HRL_LS_aussen,

    AutomaticMode := VSG_OperatingModes.F1 AND NOT VSG_OperatingModes.D2
);

VSG_Compressor := VSG_Skill_SuctionProcess.DO_CompressorVSG;
VSG_Valve := VSG_Skill_SuctionProcess.DO_ValveVSG;

VSG_ErrorDetected := VSG_Skill_SuctionProcess.VSG_ErrorDetected;
VSG_ErrorCode := VSG_Skill_SuctionProcess.VSG_ErrorCode;


VSG_DiagnosisHandler(
    Diagnose_gefordert := VSG_OperatingModes.D2,
    ErrorDetectedRaw := VSG_Skill_SuctionProcess.VSG_ErrorDetected,
    Reset := ResetButton
);


VSG_ControlOfOutputs(
    F4 := VSG_OperatingModes.F4,
    F1 := VSG_OperatingModes.F1,
    A2 := VSG_OperatingModes.A2,
    A1 := VSG_OperatingModes.A1,
    A6 := VSG_OperatingModes.A6,
    Start := VSG_OperatingModes.Start,

    VSG_VertikalDown01 := VSG_MoveVerticalDown01,
    VSG_VertikalDown02 := VSG_MoveVerticalDown02,
    VSG_VertikalUp01 := VSG_MoveVerticalUp01,
    VSG_VertikalUp02 := VSG_MoveVerticalUp02,

    VSG_HorizontalForwards01 := VSG_MoveHorizontalForwards01,
    VSG_HorizontalForwards02 := VSG_MoveHorizontalForwards02,
    VSG_HorizontalBackwards01 := VSG_MoveHorizontalBackwards01,
    VSG_HorizontalBackwards02 := VSG_MoveHorizontalBackwards02,

    VSG_RotationCW01 := VSG_MoveRotationCW01,
    VSG_RotationCW02 := VSG_MoveRotationCW02,
    VSG_RotationCCW01 := VSG_MoveRotationCCW01,
    VSG_RotationCCW02 := VSG_MoveRotationCCW02,

    VSG_Compressor := VSG_Compressor,
    VSG_Valve := VSG_Valve,

    Init_VSG_VertikalUp := Init_VSG_VertikalUp,
    Init_VSG_VertikalDown := Init_VSG_VertikalDown,
    Init_VSG_HorizontalForwards := Init_VSG_HorizontalForwards,
    Init_VSG_HorizontalBackwards := Init_VSG_HorizontalBackwards,
    Init_VSG_RotationCW := Init_VSG_RotationCW,
    Init_VSG_RotationCCW := Init_VSG_RotationCCW
);


IF GVL_Sim.bSimMode THEN

    GVL_VSG_Sim.VSG_MOT_vertikal_runter := VSG_ControlOfOutputs.MoveVerticalDown;
    GVL_VSG_Sim.VSG_MOT_vertikal_hoch := VSG_ControlOfOutputs.MoveVerticalUp;

    GVL_VSG_Sim.VSG_MOT_horizontal_vorwaerts := VSG_ControlOfOutputs.MoveHorizontalForwards;
    GVL_VSG_Sim.VSG_MOT_horizontal_rueckwaerts := VSG_ControlOfOutputs.MoveHorizontalBackwards;

    GVL_VSG_Sim.VSG_MOT_drehen_CW := VSG_ControlOfOutputs.MoveRotationCW;
    GVL_VSG_Sim.VSG_MOT_drehen_CCW := VSG_ControlOfOutputs.MoveRotationCCW;

    GVL_VSG_Sim.VSG_Kompressor := VSG_ControlOfOutputs.CompressorON;
    GVL_VSG_Sim.VSG_MV_Vakuum := VSG_ControlOfOutputs.ValveON;

ELSE

    GVL_VSG.VSG_MOT_vertikal_runter := VSG_ControlOfOutputs.MoveVerticalDown;
    GVL_VSG.VSG_MOT_vertikal_hoch := VSG_ControlOfOutputs.MoveVerticalUp;

    GVL_VSG.VSG_MOT_horizontal_vorwaerts := VSG_ControlOfOutputs.MoveHorizontalForwards;
    GVL_VSG.VSG_MOT_horizontal_rueckwaerts := VSG_ControlOfOutputs.MoveHorizontalBackwards;

    GVL_VSG.VSG_MOT_drehen_CW := VSG_ControlOfOutputs.MoveRotationCW;
    GVL_VSG.VSG_MOT_drehen_CCW := VSG_ControlOfOutputs.MoveRotationCCW;

    GVL_VSG.VSG_Kompressor := VSG_ControlOfOutputs.CompressorON;
    GVL_VSG.VSG_MV_Vakuum := VSG_ControlOfOutputs.ValveON;

END_IF;

//GEMMA_Mappings
IF VSG_OperatingModes.A1 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.A1';
ELSIF VSG_OperatingModes.A2 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.A2';
ELSIF VSG_OperatingModes.A5 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.A5';
ELSIF VSG_OperatingModes.A6 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.A6';
ELSIF VSG_OperatingModes.F1 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.F1';
ELSIF VSG_OperatingModes.F4 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.F4';
ELSIF VSG_OperatingModes.D1 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.D1';
ELSIF VSG_OperatingModes.D3 THEN
    sCurrentGemmaState := 'VSG_OperatingModes.D3';
END_IF;

IF NOT VSG_OperatingModes.D2 THEN
    sLastNonFailureGemmaState := sCurrentGemmaState;
END_IF;

rtD2(CLK := VSG_OperatingModes.D2);

IF rtD2.Q THEN
    OPCUA.LastGEMMAStateBeforeFailure := sLastNonFailureGemmaState;
END_IF;
